arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // EF Core 9 breaking change: Migrate() can no longer run inside a
        // user-opened transaction. Run it at the top level instead; Migrate()
        // manages its own transactions internally.
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

